/// 注入到 workbench 的 JavaScript 脚本模板
///
/// 该脚本在 Cursor 启动时执行，提供无缝切号能力。

/// 构建注入脚本
pub fn build(port: u16) -> String {
    format!(
        r##"
/* __MYCURSOR_SEAMLESS__ */
;(function(){{
"use strict";
var PORT={port};
function clr(el){{while(el.firstChild)el.removeChild(el.firstChild)}}
function mcS(){{if(document.getElementById('mc-st'))return;var s=document.createElement('style');s.id='mc-st';s.textContent='@keyframes mcFI{{from{{opacity:0;transform:translateX(40px)}}to{{opacity:1;transform:translateX(0)}}}}@keyframes mcSU{{from{{opacity:0;transform:translateY(16px)}}to{{transform:translateY(0);opacity:1}}}}#mc-btn{{transition:opacity .2s,box-shadow .2s}}#mc-btn:hover{{opacity:1!important;box-shadow:0 4px 20px rgba(0,0,0,.5)!important}}#mc-btn.mc-drag{{opacity:1!important;box-shadow:0 0 0 2px #4fc3f7!important;cursor:grabbing!important}}';document.head.appendChild(s)}}
function notif(m,c){{try{{var d=document.getElementById('mc-n')||function(){{var d=document.createElement('div');d.id='mc-n';d.style.cssText='position:fixed;top:20px;right:20px;z-index:999999;display:flex;flex-direction:column;gap:8px;max-width:420px;pointer-events:auto';document.body.appendChild(d);return d}}();var n=document.createElement('div');n.style.cssText='background:#1e1e1e;border:1px solid #333;border-left:3px solid '+c+';padding:12px 16px;border-radius:8px;box-shadow:0 4px 16px rgba(0,0,0,.5);color:#ccc;font-size:13px;display:flex;align-items:center;gap:10px;animation:mcFI .3s ease';var ic=document.createElement('span');ic.style.cssText='font-size:16px;flex-shrink:0';ic.textContent=c==='#4ec9b0'?'\u2713':'\u2717';n.appendChild(ic);var tx=document.createElement('span');tx.textContent=m;n.appendChild(tx);d.appendChild(n);setTimeout(function(){{n.style.opacity='0';n.style.transition='opacity .3s';setTimeout(function(){{n.remove();if(d.children.length===0)d.remove()}},300)}},5000)}}catch(e){{}}}}
var SL={{'free':{{t:'Free',c:'#4a89dc',b:'rgba(74,137,220,.12)'}},'pro':{{t:'Pro',c:'#a855f7',b:'rgba(168,85,247,.15)'}},'pro_plus':{{t:'Pro+',c:'#a855f7',b:'rgba(168,85,247,.15)'}},'ultra':{{t:'Ultra',c:'#f59e0b',b:'rgba(245,158,11,.15)'}},'token_expired':{{t:'\u5df2\u5931\u6548',c:'#f48771',b:'rgba(244,135,113,.15)'}}}};
function SI(s){{return SL[s]||{{t:s||'\u672a\u77e5',c:'#888',b:'rgba(136,136,136,.12)'}}}}
function mkBtn(){{if(document.getElementById('mc-btn'))return;var b=document.createElement('div');b.id='mc-btn';var pos;try{{pos=JSON.parse(localStorage.getItem('mc-btn-pos'))}}catch(e){{}}var ix=pos&&pos.r!=null?pos.r:20,iy=pos&&pos.b!=null?pos.b:12;b.style.cssText='position:fixed;bottom:'+iy+'px;right:'+ix+'px;z-index:999998;width:26px;height:26px;border-radius:50%;background:linear-gradient(135deg,#0e639c,#1177bb);color:#fff;display:flex;align-items:center;justify-content:center;cursor:pointer;box-shadow:0 2px 8px rgba(0,0,0,.35);font-size:12px;user-select:none;opacity:.5';b.textContent='\u26a1';b.title='\u70b9\u51fb\u5207\u6362\u8d26\u53f7';var dragged=false,startX,startY,startR,startB;b.addEventListener('mousedown',function(e){{e.preventDefault();dragged=false;startX=e.clientX;startY=e.clientY;startR=parseInt(b.style.right)||0;startB=parseInt(b.style.bottom)||0;b.classList.add('mc-drag');function onMove(e){{var dx=e.clientX-startX,dy=e.clientY-startY;if(!dragged&&(Math.abs(dx)>3||Math.abs(dy)>3))dragged=true;if(dragged){{b.style.right=Math.max(0,Math.min(window.innerWidth-30,startR-dx))+'px';b.style.bottom=Math.max(0,Math.min(window.innerHeight-30,startB-dy))+'px'}}}}function onUp(){{document.removeEventListener('mousemove',onMove);document.removeEventListener('mouseup',onUp);b.classList.remove('mc-drag');if(dragged){{try{{localStorage.setItem('mc-btn-pos',JSON.stringify({{r:parseInt(b.style.right),b:parseInt(b.style.bottom)}}))}}catch(e){{}}}}else{{fetchPick()}}}}document.addEventListener('mousemove',onMove);document.addEventListener('mouseup',onUp)}});document.body.appendChild(b)}}
function fetchPick(){{(async function(){{try{{var r=await fetch('http://127.0.0.1:'+PORT+'/api/accounts');var d=await r.json();if(d.code===0&&d.data&&d.data.length)pick(d.data);else notif('\u6ca1\u6709\u53ef\u7528\u8d26\u53f7','#f48771')}}catch(e){{notif('\u8fde\u63a5\u5931\u8d25','#f48771')}}}})()}}
function mkP(txt,act,fn){{var p=document.createElement('span');p.textContent=txt;p.style.cssText='padding:2px 10px;border-radius:12px;font-size:11px;cursor:pointer;transition:all .15s;user-select:none;white-space:nowrap;'+(act?'background:rgba(14,99,156,.3);color:#4fc3f7;border:1px solid rgba(14,99,156,.5)':'background:transparent;color:#888;border:1px solid #3c3c3c');p.onclick=fn;return p}}
function pick(accs){{var old=document.getElementById('mc-pick');if(old)old.remove();var subMap={{}},tagMap={{}};accs.forEach(function(a){{var s=a.subscription_type||'unknown';subMap[s]=(subMap[s]||0)+1;(a.tags||[]).forEach(function(t){{tagMap[t]=(tagMap[t]||0)+1}})}});var subKeys=Object.keys(subMap),tagKeys=Object.keys(tagMap);var fS='all',fT='';function getF(){{return accs.filter(function(a){{if(fS!=='all'&&(a.subscription_type||'unknown')!==fS)return false;if(fT&&(!a.tags||a.tags.indexOf(fT)===-1))return false;return true}})}}var o=document.createElement('div');o.id='mc-pick';o.style.cssText='position:fixed;inset:0;background:rgba(0,0,0,.5);z-index:999999;display:flex;align-items:center;justify-content:center;backdrop-filter:blur(3px)';var modal=document.createElement('div');modal.style.cssText='background:#1e1e1e;border:1px solid #3c3c3c;border-radius:12px;max-width:520px;width:92%;max-height:80vh;display:flex;flex-direction:column;box-shadow:0 12px 40px rgba(0,0,0,.6);animation:mcSU .25s ease';var hdr=document.createElement('div');hdr.style.cssText='padding:14px 20px;border-bottom:1px solid #2d2d2d;display:flex;align-items:center;justify-content:space-between';var tl=document.createElement('div');tl.style.cssText='display:flex;align-items:center;gap:10px';var tt=document.createElement('span');tt.style.cssText='color:#e0e0e0;font-size:15px;font-weight:600';tt.textContent='\u5207\u6362\u8d26\u53f7';tl.appendChild(tt);var cnt=document.createElement('span');cnt.style.cssText='color:#666;font-size:12px;margin-left:8px';tl.appendChild(cnt);var xb=document.createElement('button');xb.textContent='\u2715';xb.style.cssText='background:none;border:none;color:#666;font-size:18px;cursor:pointer;padding:4px 8px;border-radius:6px';xb.onclick=function(){{o.remove()}};hdr.appendChild(tl);hdr.appendChild(xb);modal.appendChild(hdr);var fb=document.createElement('div');fb.style.cssText='padding:10px 16px;border-bottom:1px solid #2d2d2d;display:flex;flex-direction:column;gap:6px';var sr=document.createElement('div');sr.style.cssText='display:flex;flex-wrap:wrap;gap:4px;align-items:center';var trow=document.createElement('div');trow.style.cssText='display:flex;flex-wrap:wrap;gap:4px;align-items:center';function rflt(){{clr(sr);sr.appendChild(mkP('\u5168\u90e8 ('+accs.length+')',fS==='all',function(){{fS='all';rflt();rList()}}));subKeys.forEach(function(k){{var i=SI(k);sr.appendChild(mkP(i.t+' ('+subMap[k]+')',fS===k,function(){{fS=k;rflt();rList()}}))}});if(tagKeys.length>0){{clr(trow);trow.appendChild(mkP('\u5168\u90e8',fT==='',function(){{fT='';rflt();rList()}}));tagKeys.forEach(function(t){{trow.appendChild(mkP(t+' ('+tagMap[t]+')',fT===t,function(){{fT=t;rflt();rList()}}))}})}}}}rflt();fb.appendChild(sr);if(tagKeys.length>0)fb.appendChild(trow);modal.appendChild(fb);var ls=document.createElement('div');ls.style.cssText='padding:8px;overflow-y:auto;flex:1';function rList(){{clr(ls);var fl=getF();cnt.textContent=fl.length===accs.length?('\u5171 '+accs.length+' \u4e2a'):('\u663e\u793a '+fl.length+' / '+accs.length);if(fl.length===0){{var emp=document.createElement('div');emp.style.cssText='padding:32px;text-align:center;color:#555;font-size:13px';emp.textContent='\u6ca1\u6709\u5339\u914d\u7684\u8d26\u53f7';ls.appendChild(emp);return}}fl.forEach(function(a){{var it=document.createElement('div');it.style.cssText='padding:10px 14px;margin:2px 0;border-radius:8px;cursor:pointer;display:flex;align-items:center;gap:12px;transition:background .12s';it.onmouseover=function(){{it.style.background='#2a2d2e'}};it.onmouseout=function(){{it.style.background='transparent'}};var av=document.createElement('div');av.style.cssText='width:34px;height:34px;border-radius:50%;background:#0e639c;color:#fff;display:flex;align-items:center;justify-content:center;font-size:14px;font-weight:600;flex-shrink:0';av.textContent=(a.email||'?')[0].toUpperCase();var inf=document.createElement('div');inf.style.cssText='flex:1;min-width:0';var em=document.createElement('div');em.style.cssText='color:#ccc;font-size:13px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap';em.textContent=a.email||'';inf.appendChild(em);it.appendChild(av);it.appendChild(inf);it.onclick=function(){{o.remove();doSwitch(a)}};ls.appendChild(it)}})}}rList();modal.appendChild(ls);o.appendChild(modal);o.onclick=function(e){{if(e.target===o)o.remove()}};document.body.appendChild(o)}}
function doSwitch(a){{(async function(){{try{{var r=await fetch('http://127.0.0.1:'+PORT+'/api/switch',{{method:'POST',headers:{{'Content-Type':'application/json'}},body:JSON.stringify({{email:a.email}})}});var d=await r.json();if(d.code===0&&d.data&&d.data.token){{var auth=window.__mcAuthService;if(auth&&'localOverrideAccessToken' in auth){{auth.localOverrideAccessToken=d.data.token;if(d.data.refresh_token)auth.refreshToken=function(){{return d.data.refresh_token}};if(!auth.__mcPatched){{auth.__mcPatched=true;auth.storeAccessRefreshToken=function(r,s){{auth.localOverrideAccessToken=r}}}}if(d.data.machine_ids){{var mi=d.data.machine_ids;if(mi['telemetry.machineId'])auth._machineId=mi['telemetry.machineId'];if(mi['telemetry.macMachineId'])auth._macMachineId=mi['telemetry.macMachineId']}}auth.notifyLoginChangedListeners(true);var newEmail=d.data.email||a.email;window.__mcCurrentEmail=newEmail;var emailEl=document.querySelector('.cursor-settings-sidebar-header-email');if(emailEl)emailEl.textContent=newEmail;notif('\u5df2\u5207\u6362\u5230 '+newEmail,'#4ec9b0')}}else{{notif('Auth \u672a\u5c31\u7eea','#f48771')}}}}else{{notif(d.msg||'\u5207\u6362\u5931\u8d25','#f48771')}}}}catch(err){{notif('\u5207\u6362\u5931\u8d25','#f48771')}}}})()}}
function watchEmail(){{new MutationObserver(function(){{if(!window.__mcCurrentEmail)return;var el=document.querySelector('.cursor-settings-sidebar-header-email');if(el&&el.textContent!==window.__mcCurrentEmail)el.textContent=window.__mcCurrentEmail}}).observe(document.body,{{childList:true,subtree:true}})}}
function boot(){{if(document.body){{mcS();mkBtn();watchEmail()}}else setTimeout(boot,300)}}
boot();
}})();
"##,
        port = port,
    )
}
